        var _req = URLRequest(url: URL(string: _baseURL + "/fixtures/value_dependency_injection_success/api/config")!)
        _req.httpMethod = "GET"
        var response: HTTPURLResponse?
        var _responseData: Data?
        let _sema = DispatchSemaphore(value: 0)
        let _session = URLSession(configuration: .ephemeral, delegate: AlefE2ENoRedirectDelegate(), delegateQueue: nil)
        _session.dataTask(with: _req) { data, resp, _ in
            response = resp as? HTTPURLResponse
            _responseData = data
            _sema.signal()
        }.resume()
        _sema.wait()
        let _resp = try XCTUnwrap(response)
        XCTAssertEqual(_resp.statusCode, 200)
        let _expected = try JSONSerialization.jsonObject(with: "{\"app_name\":\"SpikardApp\",\"max_connections\":100,\"version\":\"1.0.0\"}".data(using: .utf8)!)
        let _actual = try JSONSerialization.jsonObject(with: XCTUnwrap(_responseData))
        XCTAssertEqual(NSDictionary(dictionary: _expected as? [String: AnyHashable] ?? [:]), NSDictionary(dictionary: _actual as? [String: AnyHashable] ?? [:]))
    }

}
